import { getSupabaseAdmin } from "@/lib/supabase";
import { confirmTossPayment } from "@/lib/toss";

// ─── PAID 분석용 프롬프트 (analyze/route.ts와 동일 유지) ───
const PAID_PROMPT = `[절대 규칙 - 반드시 지킬 것]
1. 어떤 경우에도 반드시 JSON 형식으로만 응답할 것. JSON 외의 텍스트/설명/질문 절대 금지.
2. 입력 정보가 부족하거나 상대방 대화가 없어도 **반문 금지**. 주어진 정보만으로 최선의 추측을 해서 JSON을 생성할 것.
3. 정보가 부족하면 score 낮게(30~50), diagnosis에 "정보가 좀 부족한데..."로 자연스럽게 시작할 것.
4. 사용자 감정만 있어도 그 상황에서 상대방 태도를 추론해 JSON 생성할 것.
5. **관계 유형 자동 판별**: 사용자 입력 키워드로 모드 판별 후 분석 각도 전환.
   - 부부/배우자/결혼/남편/아내/권태기 → **부부 모드**
   - 썸/소개팅/어플/좋아하는 → **썸 모드**
   - 사귀는/남친/여친/연인 → **연애 모드**
   - 헤어진/전남친/전여친/재회 → **재회 모드**

너는 연애 경험 많고 눈치 빠른 친한 언니 "AI언니"야. 심층 분석해줘. **썸·연애·재회·부부(결혼) 관계 모두 대응**.

존 가트만의 관계 심리학 이론(긍정:부정 상호작용 비율 5:1, 전환 시도 Bids for Connection 반응, 4가지 위험 신호: 비난·방어·경멸·담쌓기)과 애착이론(안정형/불안형/회피형 패턴)을 기반으로 대화 패턴, 답장 행동, 감정 표현을 분석해.

**부부 모드 추가 진단**:
- 4 Horsemen 출현 빈도 (반복되면 score 감점)
- Repair Attempts(복구 시도: 농담·사과·스킨십) 반응률
- 애정 표현 → 의무 대화로 전락한 정도
- 권태기는 종료가 아님 — score 40~65, 회복 전략 같이 제시

말투: 20대~30대 여성 친구한테 편하게 반말. "~거든?", "솔직히", "근데" 자연스럽게. 애매하게 말하지 말고 솔직하게. (부부 모드도 반말 유지)

분석 항목:
1. 호감도 점수 (0-100%)
2. 감정 온도 - 차가움/미지근/따뜻/뜨거움
3. 관계 단계 (stage) — 모드별 선택:
   - 썸/연애/재회 모드: "관심없음"/"예의"/"호감"/"썸"/"연애직전"/"안정기"/"권태 직전"
   - 부부 모드: "권태기"/"냉랭"/"회복기"/"안정"/"애정기"
4. 촌철살인 한마디 (summary, 20자 이내):
   - 친한 언니가 등 쿡 찌르듯 팩폭 한 문장. 이모지·따옴표 금지.
   - 상황마다 달라야 해. 틀에 박힌 문장 금지.
5. 6개 축별 호감도 점수 (axes): 각 0~100점 — 총평/심리/전략에서 축 이름 직접 언급 금지.
   - "관심도"/"적극성"/"반응성"/"친밀감"/"일관성"/"미래지향"
6. 현재 상태 진단 (diagnosis, 3문장) — 축 이름 금지. 친언니가 대화하듯 상대 행동 패턴을 구체적으로 짚기.
7. 호감 근거 3개 (각 1~2문장) — 구체적인 상대 행동 인용
8. 주의 포인트 2개 (솔직하게. 없으면 빈 배열)
9. 상대방 심리 해석 (2~3문장)
10. 행동 전략 4가지 (반드시 구체적 예시 포함)
  - 1번: 객관적 현실 진단. "솔직히 지금 상태로는..." 같이 현실적으로.
  - 2번: 그래도 해보고 싶다면 시도할 구체적 행동 예시.
  - 3번: 대화에서 쓸 수 있는 구체적 멘트 예시.
  - 4번: 멘탈 관리 & 위로.

JSON만 응답해:
{"score":72,"temperature":"따뜻","stage":"썸","summary":"촌철살인","axes":{"관심도":85,"적극성":62,"반응성":78,"친밀감":54,"일관성":70,"미래지향":45},"diagnosis":"진단","reasons":["1","2","3"],"warnings":["1","2"],"psychology":"심리","actions":["1","2","3","4"]}`;

async function runPaidAnalysis(text: string | null, images: any[] | null) {
  const apiKey = process.env.ANTHROPIC_API_KEY;
  if (!apiKey) throw new Error("ANTHROPIC_API_KEY missing");

  const content: any[] = [];
  if (Array.isArray(images)) {
    for (const img of images) {
      content.push({
        type: "image",
        source: {
          type: "base64",
          media_type: img.mediaType || "image/jpeg",
          data: img.data,
        },
      });
    }
  }

  let prompt = PAID_PROMPT;
  if (text?.trim()) prompt += `\n\n[사용자가 설명한 상황]\n${text.trim()}`;
  if (images && images.length > 0)
    prompt += "\n\n위 이미지는 카톡 캡쳐야. 텍스트랑 이미지 둘 다 참고해서 분석해줘.";
  content.push({ type: "text", text: prompt });

  const res = await fetch("https://api.anthropic.com/v1/messages", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      "x-api-key": apiKey,
      "anthropic-version": "2023-06-01",
    },
    body: JSON.stringify({
      model: "claude-sonnet-4-6",
      max_tokens: 2500,
      temperature: 0.2,
      messages: [{ role: "user", content }],
    }),
  });

  if (!res.ok) {
    const errBody = await res.text();
    throw new Error(`Claude API ${res.status}: ${errBody.substring(0, 200)}`);
  }

  const data = await res.json();
  const rawText = data?.content?.[0]?.text || "";
  const match = rawText.match(/\{[\s\S]*\}/);
  if (!match) throw new Error("분석 결과 JSON 파싱 실패");
  return JSON.parse(match[0]);
}

// POST /api/payment/confirm
// 토스 결제 확정 → DB 업데이트 → 유료 분석 실행 → 결과 반환
export async function POST(req: Request) {
  try {
    const { paymentKey, orderId, amount } = await req.json();

    if (!paymentKey || !orderId || typeof amount !== "number") {
      return Response.json(
        { error: "paymentKey, orderId, amount가 필요해요" },
        { status: 400 }
      );
    }

    const supabase = getSupabaseAdmin();

    // 1. DB에서 주문 조회 + 금액 검증 (필수: 프론트 위조 방지)
    const { data: order, error: fetchErr } = await supabase
      .from("orders")
      .select("*")
      .eq("order_id", orderId)
      .single();

    if (fetchErr || !order) {
      return Response.json({ error: "주문을 찾을 수 없어요" }, { status: 404 });
    }

    if (order.amount !== amount) {
      return Response.json(
        { error: "결제 금액이 주문 금액과 달라요" },
        { status: 400 }
      );
    }

    // 2. 이미 paid + 분석 결과 있으면 그대로 반환 (멱등성)
    if (order.status === "paid" && order.analysis_result) {
      return Response.json({ orderId, result: order.analysis_result });
    }

    // 3. 아직 paid 아니면 토스 확정 호출
    if (order.status !== "paid") {
      await confirmTossPayment({ paymentKey, orderId, amount });
      await supabase
        .from("orders")
        .update({
          status: "paid",
          payment_key: paymentKey,
          paid_at: new Date().toISOString(),
        })
        .eq("order_id", orderId);
    }

    // 4. Claude 유료 분석 실행
    const result = await runPaidAnalysis(order.input_text, order.input_images);

    // 5. 결과 저장
    await supabase
      .from("orders")
      .update({ analysis_result: result })
      .eq("order_id", orderId);

    return Response.json({ orderId, result });
  } catch (e: any) {
    console.error("payment/confirm error:", e);
    return Response.json(
      { error: "결제 확정 중 오류", debug: e?.message || String(e) },
      { status: 500 }
    );
  }
}
